+    // Probe test: table-based operations with edge cases
+    #[test]
+    fn test_probe_table_operations() {
+        let conn = Connection::open(":memory:").unwrap();
+
+        conn.execute("CREATE TABLE t1 (id INTEGER PRIMARY KEY, val TEXT, num REAL);")
