+    // Probe: advanced/edge-case SQL patterns
+    #[test]
+    fn test_probe_advanced_patterns() {
+        let conn = Connection::open(":memory:").unwrap();
+
+        conn.execute("CREATE TABLE nums (n INTEGER);").unwrap();
