+            conn.execute_with_params("INSERT INTO nums VALUES (?1);", &[SqliteValue::Integer(i)])
+                .unwrap();
+        }
+
+        // Correlated subquery
+        let rows = conn
+            .query("SELECT n FROM nums AS a WHERE n > (SELECT AVG(n) FROM nums);")
+            .unwrap();
